import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { productAPI } from '../../services/api';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import StarIcon from '@mui/icons-material/Star';
import StarBorderIcon from '@mui/icons-material/StarBorder';
import LocalShippingIcon from '@mui/icons-material/LocalShipping';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import ThermostatIcon from '@mui/icons-material/Thermostat';
import toast from 'react-hot-toast';

const ProductDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { user } = useAuth();

  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedVariant, setSelectedVariant] = useState(null);
  const [quantity, setQuantity] = useState(1);
  const [adding, setAdding] = useState(false);
  const [activeImage, setActiveImage] = useState(0);
  const [reviewForm, setReviewForm] = useState({ rating: 5, comment: '' });
  const [submittingReview, setSubmittingReview] = useState(false);

  useEffect(() => {
    productAPI.getOne(id)
      .then(({ data }) => {
        setProduct(data.data);
        if (data.data.variants?.length > 0) setSelectedVariant(data.data.variants[0]);
      })
      .catch(() => navigate('/shop'))
      .finally(() => setLoading(false));
  }, [id, navigate]);

  const price = product ? product.basePrice + (selectedVariant?.priceModifier || 0) : 0;
  const inStock = selectedVariant ? selectedVariant.stock > 0 : false;
  const maxQty = selectedVariant?.stock || 0;

  const handleAddToCart = async () => {
    if (!user) { toast.error('Please sign in'); navigate('/login'); return; }
    setAdding(true);
    try {
      await addToCart(product._id, selectedVariant?._id, quantity);
    } finally {
      setAdding(false);
    }
  };

  const handleReviewSubmit = async (e) => {
    e.preventDefault();
    if (!user) { navigate('/login'); return; }
    setSubmittingReview(true);
    try {
      await productAPI.addReview(id, reviewForm);
      toast.success('Review submitted!');
      // Refresh product
      const { data } = await productAPI.getOne(id);
      setProduct(data.data);
      setReviewForm({ rating: 5, comment: '' });
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to submit review');
    } finally {
      setSubmittingReview(false);
    }
  };

  if (loading) return (
    <div className="max-w-7xl mx-auto px-4 py-16 animate-pulse">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="aspect-square bg-tea-100 rounded-2xl" />
        <div className="space-y-4">
          <div className="h-6 bg-tea-100 rounded w-1/4" />
          <div className="h-10 bg-tea-100 rounded w-3/4" />
          <div className="h-4 bg-tea-100 rounded w-full" />
          <div className="h-4 bg-tea-100 rounded w-2/3" />
        </div>
      </div>
    </div>
  );

  if (!product) return null;

  const images = product.images?.length ? product.images : [product.thumbnail];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        {/* Images */}
        <div>
          <div className="aspect-square rounded-2xl overflow-hidden bg-tea-50 mb-3">
            <img
              src={images[activeImage]}
              alt={product.name}
              className="w-full h-full object-cover"
              onError={(e) => { e.target.src = 'https://images.unsplash.com/photo-1556679343-c7306c1976bc?w=600'; }}
            />
          </div>
          {images.length > 1 && (
            <div className="flex gap-2">
              {images.map((img, i) => (
                <button
                  key={i}
                  onClick={() => setActiveImage(i)}
                  className={`w-16 h-16 rounded-lg overflow-hidden border-2 transition-colors ${
                    i === activeImage ? 'border-tea-600' : 'border-transparent'
                  }`}
                >
                  <img src={img} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Info */}
        <div>
          <span className="badge bg-tea-100 text-tea-700 mb-3">{product.category.replace('-', ' ')}</span>
          <h1 className="font-display text-3xl lg:text-4xl text-tea-900 mb-2">{product.name}</h1>

          {/* Rating */}
          <div className="flex items-center gap-2 mb-4">
            <div className="flex text-amber-400">
              {[1,2,3,4,5].map((s) => (
                s <= Math.round(product.rating)
                  ? <StarIcon key={s} fontSize="small" />
                  : <StarBorderIcon key={s} fontSize="small" />
              ))}
            </div>
            <span className="text-sm text-gray-500">({product.numReviews} reviews)</span>
          </div>

          {/* Price */}
          <div className="text-3xl font-bold text-tea-800 mb-6">${price.toFixed(2)}</div>

          <p className="text-gray-600 leading-relaxed mb-6">{product.description}</p>

          {/* Brewing info */}
          {(product.brewingTime || product.temperature) && (
            <div className="flex gap-4 mb-6 p-4 bg-tea-50 rounded-xl">
              {product.brewingTime && (
                <div className="flex items-center gap-2 text-sm text-tea-700">
                  <AccessTimeIcon fontSize="small" />
                  <span>{product.brewingTime}</span>
                </div>
              )}
              {product.temperature && (
                <div className="flex items-center gap-2 text-sm text-tea-700">
                  <ThermostatIcon fontSize="small" />
                  <span>{product.temperature}</span>
                </div>
              )}
            </div>
          )}

          {/* Variant selector */}
          {product.variants?.length > 0 && (
            <div className="mb-6">
              <label className="text-sm font-medium text-gray-700 mb-2 block">Size</label>
              <div className="flex flex-wrap gap-2">
                {product.variants.map((v) => (
                  <button
                    key={v._id}
                    onClick={() => { setSelectedVariant(v); setQuantity(1); }}
                    disabled={v.stock === 0}
                    className={`px-4 py-2 rounded-lg border text-sm font-medium transition-all ${
                      selectedVariant?._id === v._id
                        ? 'border-tea-600 bg-tea-600 text-white'
                        : v.stock === 0
                        ? 'border-gray-200 text-gray-400 cursor-not-allowed line-through'
                        : 'border-gray-300 text-gray-700 hover:border-tea-400'
                    }`}
                  >
                    {v.name}
                    {v.priceModifier > 0 && <span className="ml-1 text-xs opacity-70">+${v.priceModifier}</span>}
                  </button>
                ))}
              </div>
              {selectedVariant && (
                <p className="text-xs text-gray-500 mt-2">
                  {selectedVariant.stock > 0
                    ? `${selectedVariant.stock} in stock`
                    : <span className="text-red-500">Out of stock</span>}
                </p>
              )}
            </div>
          )}

          {/* Quantity */}
          <div className="flex items-center gap-4 mb-6">
            <div className="flex items-center border border-gray-300 rounded-lg overflow-hidden">
              <button
                onClick={() => setQuantity((q) => Math.max(1, q - 1))}
                className="px-3 py-2 hover:bg-tea-50 text-gray-600 transition-colors"
              >−</button>
              <span className="px-4 py-2 font-medium text-gray-800 min-w-[3rem] text-center">{quantity}</span>
              <button
                onClick={() => setQuantity((q) => Math.min(maxQty, q + 1))}
                disabled={quantity >= maxQty}
                className="px-3 py-2 hover:bg-tea-50 text-gray-600 transition-colors disabled:opacity-40"
              >+</button>
            </div>
            <button
              onClick={handleAddToCart}
              disabled={!inStock || adding}
              className="flex-1 btn-primary py-3 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {adding ? 'Adding...' : inStock ? 'Add to Cart' : 'Out of Stock'}
            </button>
          </div>

          <div className="flex items-center gap-2 text-sm text-gray-500">
            <LocalShippingIcon fontSize="small" className="text-sage-500" />
            <span>Free shipping on orders over $50</span>
          </div>

          {/* Tags */}
          {product.tags?.length > 0 && (
            <div className="mt-6 flex flex-wrap gap-2">
              {product.tags.map((tag) => (
                <span key={tag} className="badge bg-gray-100 text-gray-600 capitalize">{tag}</span>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Reviews Section */}
      <div className="mt-16 border-t border-tea-100 pt-12">
        <h2 className="font-display text-2xl text-tea-900 mb-8">Customer Reviews</h2>
        <div className="grid lg:grid-cols-2 gap-12">
          {/* Review list */}
          <div className="space-y-5">
            {product.reviews?.length === 0 ? (
              <p className="text-gray-500">No reviews yet. Be the first!</p>
            ) : (
              product.reviews.map((r) => (
                <div key={r._id} className="card p-5">
                  <div className="flex items-center gap-3 mb-3">
                    <div className="w-9 h-9 bg-tea-200 rounded-full flex items-center justify-center text-tea-800 font-semibold text-sm">
                      {r.name[0]}
                    </div>
                    <div>
                      <p className="font-medium text-gray-800 text-sm">{r.name}</p>
                      <div className="flex text-amber-400">
                        {[1,2,3,4,5].map((s) => (
                          s <= r.rating ? <StarIcon key={s} sx={{ fontSize: 12 }} /> : <StarBorderIcon key={s} sx={{ fontSize: 12 }} />
                        ))}
                      </div>
                    </div>
                    <span className="ml-auto text-xs text-gray-400">{new Date(r.createdAt).toLocaleDateString()}</span>
                  </div>
                  <p className="text-gray-600 text-sm leading-relaxed">{r.comment}</p>
                </div>
              ))
            )}
          </div>

          {/* Write review */}
          {user && (
            <div>
              <h3 className="font-display text-lg text-tea-900 mb-4">Write a Review</h3>
              <form onSubmit={handleReviewSubmit} className="card p-5 space-y-4">
                <div>
                  <label className="text-sm font-medium text-gray-700 mb-2 block">Rating</label>
                  <div className="flex gap-1">
                    {[1,2,3,4,5].map((s) => (
                      <button
                        key={s}
                        type="button"
                        onClick={() => setReviewForm((f) => ({ ...f, rating: s }))}
                        className={`text-2xl transition-colors ${s <= reviewForm.rating ? 'text-amber-400' : 'text-gray-300'}`}
                      >★</button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="text-sm font-medium text-gray-700 mb-2 block">Comment</label>
                  <textarea
                    value={reviewForm.comment}
                    onChange={(e) => setReviewForm((f) => ({ ...f, comment: e.target.value }))}
                    required
                    rows={4}
                    className="input resize-none"
                    placeholder="Share your experience with this tea..."
                  />
                </div>
                <button type="submit" disabled={submittingReview} className="btn-primary w-full">
                  {submittingReview ? 'Submitting...' : 'Submit Review'}
                </button>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProductDetailPage;
